sql:
SELECT total_energy_production_gkwh
FROM energy_data
WHERE year = 0 AND region_id = 0 AND facility_id = 0;

SELECT SUM(total_energy_production_gkwh) AS total_energy_production_2023
FROM energy_data
WHERE year = 2023;

SELECT AVG(capacity_factor) AS average_capacity_factor
FROM energy_data
WHERE year = 2023 AND region_id = 1;

SELECT year
  FROM energy_data
  WHERE region_id = 0 AND source_id = 1;

SELECT facility_name
FROM energy_facilities
WHERE status = 'operational';

SELECT source_name
FROM energy_sources
WHERE source_id = 1;

SELECT SUM(energy_production_gkwh) AS total_energy_production_2014
FROM facility_energy_data
WHERE year = 2014;

SELECT energy_production_gkwh
FROM facility_energy_data
WHERE facility_id = 1 AND year = 2014;

